using namespace std;

long long solve(vector<vector<long long>> grid, long long k) {
    int m = grid.size();
    int n = grid[0].size();
    long long count = 0;
    for (int i = 0; i < m; ++i) {
        for (int j = 0; j < n; ++j) {
            if (grid[i][j] > 0) {
                queue<pair<int, int>> q;
                q.push({i, j});
                long long sum = 0;
                sum += grid[i][j];
                grid[i][j] = 0;
                while (!q.empty()) {
                    auto [x, y] = q.front();
