#include <vector>
#include <queue>
#include <utility>

using namespace std;

long long solve(vector<vector<long long>> grid, long long k) {
    int m = grid.size();
    int n = grid[0].size();
    long long count = 0;
    for (int i = 0; i < m; ++i) {
        for (int j = 0; j < n; ++j) {
            if (grid[i][j] > 0) {
                queue<pair<int, int>> q;
                q.push({i, j});
                long long sum = 0;
                sum += grid[i][j];
                grid[i][j] = 0;
                while (!q.empty()) {
                    auto [x, y] = q.front();
                    q.pop();
                    for (int dx = -1; dx <= 1; dx++) {
                        for (int dy = -1; dy <= 1; dy++) {
                            if (dx == 0 && dy == 0) continue;
                            int nx = x + dx;
                            int ny = y + dy;
                            if (nx >= 0 && nx < m && ny >= 0 && ny < n && grid[nx][ny] > 0) {
                                sum += grid[nx][ny];
                                grid[nx][ny] = 0;
                                q.push({nx, ny});
                            }
                        }
                    }
                }
                if (sum % k == 0) {
                    count++;
                }
            }
        }
    }
    return count;
}
